 510 |                 function findSentenceRange(rootDoc, startNode, startOffset) {
 511 |                     const sentenceEndRegex = /[.!?]/;
 512 |                     
 513 |                     // Helper: TreeWalker for linear text traversal
 514 |                     function createWalker(root) {
 515 |                         return rootDoc.createTreeWalker(root, NodeFilter.SHOW_TEXT, null, false);
 516 |                     }
 517 | 
 518 |                     // 1. BACKWARD SCAN (Find start)
 519 |                     let currentStartNode = startNode;
 520 |                     let currentStartOffset = startOffset;
 521 |                     let finalStartNode = startNode;
 522 |                     let finalStartOffset = 0;
 523 | 
 524 |                     // Check backwards inside the clicked node first
 525 |                     let textBefore = currentStartNode.textContent.substring(0, currentStartOffset);
 526 |                     let lastPuncIndex = -1;
 527 |                     
 528 |                     for(let i = textBefore.length - 1; i >= 0; i--) {
 529 |                         if(sentenceEndRegex.test(textBefore[i])) {
 530 |                             lastPuncIndex = i;
 531 |                             break;
 532 |                         }
 533 |                     }
 534 | 
 535 |                     if (lastPuncIndex !== -1) {
 536 |                         finalStartOffset = lastPuncIndex + 1;
 537 |                         // Skip space if present right after dot
 538 |                         if(currentStartNode.textContent[finalStartOffset] === ' ') finalStartOffset++;
 539 |                     } else {
 540 |                         // Walk backwards through DOM
 541 |                         const walker = createWalker(docBody);
 542 |                         walker.currentNode = currentStartNode;
 543 |                         let prevNode = walker.previousNode();
 544 |                         let foundStart = false;
 545 | 
 546 |                         while (prevNode && !foundStart) {
 547 |                             const text = prevNode.textContent;
 548 |                             for (let i = text.length - 1; i >= 0; i--) {
 549 |                                 if (sentenceEndRegex.test(text[i])) {
 550 |                                     finalStartNode = prevNode;
 551 |                                     finalStartOffset = i + 1;
 552 |                                     if(text[finalStartOffset] === ' ') finalStartOffset++;
 553 |                                     foundStart = true;
 554 |                                     break;
 555 |                                 }
 556 |                             }
 557 |                             if (!foundStart) {
 558 |                                 finalStartNode = prevNode;
 559 |                                 finalStartOffset = 0;
 560 |                                 prevNode = walker.previousNode();
 561 |                             }
 562 |                         }
 563 |                     }
 564 | 
 565 |                     // 2. FORWARD SCAN (Find end)
 566 |                     let currentEndNode = startNode;
 567 |                     let currentEndOffset = startOffset;
 568 |                     let finalEndNode = startNode;
 569 |                     let finalEndOffset = startNode.textContent.length;
 570 | 
 571 |                     let textAfter = currentEndNode.textContent.substring(currentEndOffset);
 572 |                     let nextPuncIndex = textAfter.search(sentenceEndRegex);
 573 | 
 574 |                     if (nextPuncIndex !== -1) {
 575 |                         finalEndOffset = currentEndOffset + nextPuncIndex + 1;
 576 |                     } else {
 577 |                         // Walk forwards through DOM
 578 |                         const walker = createWalker(docBody);
 579 |                         walker.currentNode = currentEndNode;
 580 |                         let nextNode = walker.nextNode();
